evaluators.evaluation_logic:
const checkpoints = [];

function parseJSON(key) {
  try { return JSON.parse(localStorage.getItem(key) || '[]'); } catch (e) { return []; }
}

const visitSummaryViewed = localStorage.getItem('task1_visitSummaryViewed') === 'true';
const bookingId = localStorage.getItem('task1_bookingId');
const timeslotIdInstr = localStorage.getItem('task1_timeslotId');

const bookings = parseJSON('admission_bookings');
const timeslots = parseJSON('admission_timeslots');
const ticketTypes = parseJSON('ticket_types');
const cartItems = parseJSON('cart_items');
const carts = parseJSON('cart');
const currentCartId = localStorage.getItem('current_cart_id');

function getDateOnly(str) {
  if (!str) return null;
  return String(str).substring(0, 10);
}

const booking = bookings.find(b => b.id === bookingId);
let tt = null;
if (booking) {
  tt = ticketTypes.find(t => t.id === booking.ticket_type_id);
}

let visitDate = null;
let isMay2026 = false;
let isSaturday = false;
if (booking && booking.visit_date) {
  visitDate = new Date(booking.visit_date);
  if (!isNaN(visitDate.getTime())) {
    const year = visitDate.getUTCFullYear();
    const month = visitDate.getUTCMonth(); // 0-based; May = 4
    const dow = visitDate.getUTCDay(); // 6 = Saturday
    isMay2026 = (year === 2026 && month === 4);
    isSaturday = (dow === 6);
  }
}

const isCorrectParty = !!booking &&
  Number(booking.adult_count) === 2 &&
  Number(booking.child_6_12_count || 0) === 1 &&
  Number(booking.child_count || 0) === 0 &&
  Number(booking.senior_count || 0) === 0;

const isGeneralEntry = !!tt && tt.code === 'general_entry';
const isEuro = !!booking && booking.currency === 'eur';

// Determine earliest available general entry timeslot on that date at or after 15:00
let earliestTs = null;
if (booking && tt) {
  const totalTickets = Number(booking.adult_count || 0) + Number(booking.child_6_12_count || 0) + Number(booking.child_count || 0) + Number(booking.senior_count || 0);
  const targetDate = getDateOnly(booking.visit_date);
  const daySlots = timeslots.filter(ts => getDateOnly(ts.date) === targetDate && ts.ticket_type_id === tt.id);
  const eligible = daySlots.filter(ts => {
    if (!ts.is_available) return false;
    if (!ts.start_time || ts.start_time < '15:00') return false;
    const remaining = Number(ts.capacity_total || 0) - Number(ts.capacity_booked || 0);
    if (remaining < totalTickets) return false;
    return true;
  });
  eligible.sort((a, b) => String(a.start_time).localeCompare(String(b.start_time)));
  earliestTs = eligible.length > 0 ? eligible[0] : null;
}

const isEarliestTimeslot = !!booking && !!earliestTs && booking.timeslot_id === earliestTs.id;
const timeslotIdMatchesInstr = !!booking && !!timeslotIdInstr && booking.timeslot_id === timeslotIdInstr;

// Check booking is in the current cart as a general admission item
let inCart = false;
if (booking && currentCartId) {
  inCart = cartItems.some(ci => ci.cart_id === currentCartId && ci.item_type === 'general_admission' && ci.admission_booking_id === booking.id);
}

const bookingQualifies = !!booking && !!tt && isCorrectParty && isGeneralEntry && isEuro && isMay2026 && isSaturday && isEarliestTimeslot;

// CP1 (0.50): Qualifying booking created for earliest eligible May 2026 Saturday 15:00+ general entry slot with correct party, and timeslot instrumentation matches
checkpoints.push({
  passed: bookingQualifies && timeslotIdMatchesInstr,
  weight: 0.50
});

// CP2 (0.30): Qualifying booking is present in the current cart (visit summary basis)
checkpoints.push({
  passed: bookingQualifies && inCart,
  weight: 0.30
});

// CP3 (0.20): Visit summary page viewed after adding qualifying booking to cart
checkpoints.push({
  passed: bookingQualifies && inCart && visitSummaryViewed,
  weight: 0.20
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseJSONKey(key) {
  try { return JSON.parse(localStorage.getItem(key) || '[]'); } catch (e) { return []; }
}

let filterParams = null;
try {
  filterParams = JSON.parse(localStorage.getItem('task2_exhibitFilterParams') || 'null');
} catch (e) {
  filterParams = null;
}
const routeOverviewViewed = localStorage.getItem('task2_routeOverviewViewed') === 'true';

const exhibits = parseJSONKey('exhibits');
const routeStopsAll = parseJSONKey('route_stops');
const routes = parseJSONKey('self_guided_routes');
const currentRouteId = localStorage.getItem('current_route_id');

const routeId = currentRouteId || (routes[0] && routes[0].id) || null;
const routeStops = routeStopsAll.filter(rs => rs.route_id === routeId);

function isPre1500Exhibit(ex) {
  if (!ex) return false;
  if (ex.era_label === 'Before 1500') return true;
  const endYear = ex.era_end_year != null ? ex.era_end_year : ex.era_start_year;
  return endYear != null && endYear <= 1499;
}

// Build qualifying stops with their exhibits
const qualifyingStops = routeStops.map(rs => {
  const ex = exhibits.find(e => e.id === rs.exhibit_id);
  return { rs, ex };
}).filter(pair => {
  const ex = pair.ex;
  if (!ex) return false;
  if (ex.region !== 'europe') return false;
  if (!isPre1500Exhibit(ex)) return false;
  const visitMinutes = Number(ex.estimated_visit_time_minutes || pair.rs.estimated_visit_time_minutes || 0);
  if (visitMinutes > 25) return false;
  return true;
});

const distinctCountries = {};
let totalVisitMinutes = 0;
for (let i = 0; i < qualifyingStops.length; i++) {
  const ex = qualifyingStops[i].ex;
  if (ex && ex.country) {
    distinctCountries[ex.country] = true;
  }
  const vm = Number(ex.estimated_visit_time_minutes || qualifyingStops[i].rs.estimated_visit_time_minutes || 0);
  totalVisitMinutes += vm;
}
const countryCount = Object.keys(distinctCountries).length;

// CP1 (0.30): Exhibits filtered with region=Europe, era=before_1500, and max visit time <=25 minutes
const filterPassed = !!filterParams &&
  filterParams.region === 'europe' &&
  filterParams.era_value === 'before_1500' &&
  (filterParams.max_estimated_visit_time_minutes == null || Number(filterParams.max_estimated_visit_time_minutes) <= 25);
checkpoints.push({
  passed: filterPassed,
  weight: 0.30
});

// CP2 (0.45): Route contains at least 4 qualifying pre-1500 European exhibits from 4 countries with total visit time <=90 minutes
const routeContentPassed = qualifyingStops.length >= 4 && countryCount >= 4 && totalVisitMinutes <= 90;
checkpoints.push({
  passed: routeContentPassed,
  weight: 0.45
});

// CP3 (0.25): Route overview viewed after building qualifying route
checkpoints.push({
  passed: routeContentPassed && routeOverviewViewed,
  weight: 0.25
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseJSONArr(key) {
  try { return JSON.parse(localStorage.getItem(key) || '[]'); } catch (e) { return []; }
}

let filterParams = null;
try {
  filterParams = JSON.parse(localStorage.getItem('task3_tourFilterParams') || 'null');
} catch (e) {
  filterParams = null;
}
const bookingReviewViewed = localStorage.getItem('task3_bookingReviewViewed') === 'true';
const bookingId = localStorage.getItem('task3_bookingId');

const programs = parseJSONArr('programs');
const sessions = parseJSONArr('program_sessions');
const bookings = parseJSONArr('program_bookings');

// Helper: extract date-only and month-year
function dateOnlyFromISO(str) {
  if (!str) return null;
  return String(str).substring(0, 10);
}
function monthYearFromISO(str) {
  if (!str) return null;
  return String(str).substring(0, 7);
}

// Identify the booking
const booking = bookings.find(b => b.id === bookingId);
let program = null;
let session = null;
if (booking) {
  program = programs.find(p => p.id === booking.program_id);
  session = sessions.find(s => s.id === booking.session_id);
}

// Compute all qualifying English guided tours on the filtered date with price <= filter max
let filterDate = filterParams && filterParams.date ? filterParams.date : null;
let filterMaxPrice = filterParams && filterParams.max_price != null ? Number(filterParams.max_price) : 25.0;

// Recognize August 2026: YYYY-08
const filterMonthYear = filterDate ? filterDate.substring(0, 7) : null;
const isFilterInAugust2026 = filterMonthYear === '2026-08';

const qualifyingTours = [];
for (let i = 0; i < programs.length; i++) {
  const p = programs[i];
  if (p.program_type !== 'guided_tour') continue;
  if (!p.is_active) continue;
  if (filterParams && filterParams.language && p.language !== filterParams.language) continue;
  if (p.language !== 'english') continue;

  // sessions on the filter date
  for (let j = 0; j < sessions.length; j++) {
    const s = sessions[j];
    if (s.program_id !== p.id) continue;
    if (filterDate && dateOnlyFromISO(s.start_datetime) !== filterDate) continue;
    if (s.price_adult != null && s.price_adult > filterMaxPrice) continue;
    // August 2026 constraint
    if (monthYearFromISO(s.start_datetime) !== '2026-08') continue;
    qualifyingTours.push({ program: p, session: s });
  }
}

let maxDuration = null;
for (let i = 0; i < qualifyingTours.length; i++) {
  const dur = Number(qualifyingTours[i].program.duration_minutes || 0);
  if (maxDuration == null || dur > maxDuration) {
    maxDuration = dur;
  }
}

const bookingIsQualifying = !!booking && !!program && !!session &&
  program.program_type === 'guided_tour' &&
  program.language === 'english' &&
  monthYearFromISO(session.start_datetime) === '2026-08' &&
  (!filterDate || dateOnlyFromISO(session.start_datetime) === filterDate) &&
  Number(session.price_adult || 0) <= filterMaxPrice &&
  Number(booking.adult_count || 0) === 1 &&
  Number(booking.child_count || 0) === 0 &&
  Number(booking.senior_count || 0) === 0 &&
  maxDuration != null &&
  Number(program.duration_minutes || 0) === maxDuration;

// CP1 (0.35): Tours filtered with language=english, date in August 2026, max_price <=25, sorted by duration descending
const filterPassed = !!filterParams &&
  filterParams.language === 'english' &&
  !!filterParams.date && filterParams.date.substring(0, 7) === '2026-08' &&
  (filterParams.max_price == null || Number(filterParams.max_price) <= 25.0) &&
  filterParams.sort_by === 'duration_desc';
checkpoints.push({
  passed: filterPassed,
  weight: 0.35
});

// CP2 (0.40): Created a booking for the longest qualifying English guided tour on that date with exactly 1 adult ticket
checkpoints.push({
  passed: bookingIsQualifying,
  weight: 0.40
});

// CP3 (0.25): Booking review page viewed for a qualifying booking
checkpoints.push({
  passed: bookingIsQualifying && bookingReviewViewed,
  weight: 0.25
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseArr(key) {
  try { return JSON.parse(localStorage.getItem(key) || '[]'); } catch (e) { return []; }
}

let filterParams = null;
try {
  filterParams = JSON.parse(localStorage.getItem('task4_articleFilterParams') || 'null');
} catch (e) {
  filterParams = null;
}
const readingListViewed = localStorage.getItem('task4_readingListViewed') === 'true';

const articles = parseArr('articles');
const lists = parseArr('reading_lists');
const items = parseArr('reading_list_items');
const currentListId = localStorage.getItem('current_reading_list_id') || (lists[0] && lists[0].id) || null;

// Determine qualifying criteria
const RANGE_START = 1800;
const RANGE_END = 1950;
const MAX_MINUTES = 10;

function articleQualifies(a) {
  if (!a) return false;
  if (a.topic !== 'aging_maturation') return false;
  const s = a.time_period_start_year;
  const e = a.time_period_end_year;
  // Overlap with 1800-1950
  if (s != null && e != null) {
    if (e < RANGE_START || s > RANGE_END) return false;
  }
  if (a.estimated_reading_time_minutes != null && a.estimated_reading_time_minutes > MAX_MINUTES) return false;
  return true;
}

const listItemsForList = items.filter(it => it.reading_list_id === currentListId);
const qualifyingItems = listItemsForList.filter(it => {
  const art = articles.find(a => a.id === it.article_id);
  return articleQualifies(art);
});

// CP1 (0.35): Articles filtered with topic=aging_maturation, time period roughly 1800–1950, and max reading time <=10
const filterPassed = !!filterParams &&
  filterParams.topic === 'aging_maturation' &&
  (filterParams.time_period_start_year == null || Number(filterParams.time_period_start_year) >= 1800) &&
  (filterParams.time_period_end_year == null || Number(filterParams.time_period_end_year) <= 1950) &&
  (filterParams.max_reading_time_minutes == null || Number(filterParams.max_reading_time_minutes) <= 10);
checkpoints.push({
  passed: filterPassed,
  weight: 0.35
});

// CP2 (0.40): At least 3 qualifying aging & maturation articles (1800–1950, <=10 min) added to the current reading list
checkpoints.push({
  passed: qualifyingItems.length >= 3,
  weight: 0.40
});

// CP3 (0.25): Reading list page viewed after adding at least 3 qualifying articles
checkpoints.push({
  passed: qualifyingItems.length >= 3 && readingListViewed,
  weight: 0.25
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

