const checkmarks = [];

function parseArray(key) {
  try { return JSON.parse(localStorage.getItem(key) || '[]'); } catch (e) { return []; }
}

const ancientRangeUsed = localStorage.getItem('task6_ancientRangeUsed') === 'true';
const modernRangeUsed = localStorage.getItem('task6_modernRangeUsed') === 'true';
const myTimelineViewed = localStorage.getItem('task6_myTimelineViewed') === 'true';

const events = parseArray('timeline_events');
const pinned = parseArray('pinned_timeline_events');

function getEventYear(ev) {
  if (!ev) return null;
  if (ev.year != null) return ev.year;
  if (ev.start_year != null) return ev.start_year;
  if (ev.end_year != null) return ev.end_year;
  return null;
}

let ancientCount = 0;
let modernCount = 0;
for (let i = 0; i < pinned.length; i++) {
  const pe = pinned[i];
  const ev = events.find(e => e.id === pe.event_id);
  const y = getEventYear(ev);
  if (y == null) continue;
  if (y >= -2000 && y <= 1) {
    ancientCount++;
  }
  if (y >= 1900 && y <= 1950) {
    modernCount++;
  }
}

const totalPinnedRelevant = ancientCount + modernCount;

// CP1 (0.40): Ancient era range used and at least 3 pinned events between 2000 BCE and 1 CE
checkmarks.push({
  passed: ancientRangeUsed && ancientCount >= 3,
  weight: 0.40
});

// CP2 (0.35): Modern era range used and at least 2 pinned events between 1900 and 1950 CE
checkmarks.push({
  passed: modernRangeUsed && modernCount >= 2,
  weight: 0.35
});

// CP3 (0.25): My Timeline view opened with at least 5 relevant pinned events total (3 ancient + 2 modern)
checkmarks.push({
  passed: myTimelineViewed && ancientCount >= 3 && modernCount >= 2 && totalPinnedRelevant >= 5,
  weight: 0.25
});

return checkmarks.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseLSArray(key) {
  try { return JSON.parse(localStorage.getItem(key) || '[]'); } catch (e) { return []; }
}

let historyFilter = null;
let scienceFilter = null;
try {
  historyFilter = JSON.parse(localStorage.getItem('task7_historyBookFilterParams') || 'null');
} catch (e) {
  historyFilter = null;
}
try {
  scienceFilter = JSON.parse(localStorage.getItem('task7_scienceBookFilterParams') || 'null');
} catch (e) {
  scienceFilter = null;
}
const cartViewed = localStorage.getItem('task7_cartViewed') === 'true';

const products = parseLSArray('products');
const cartItems = parseLSArray('cart_items');
const carts = parseLSArray('cart');
const shippingOptions = parseLSArray('shipping_options');
const currentCartId = localStorage.getItem('current_cart_id');

// CP1 (0.30): Filters used correctly for history (paperback, european_cheese_history, rating>=4, price<=30) and science (paperback, cheese_science/modern_cheese_production, rating>=4, price<=25)
function historyFilterOk(f) {
  if (!f) return false;
  if (f.format !== 'paperback') return false;
  if (f.topic !== 'european_cheese_history') return false;
  if (f.min_rating != null && Number(f.min_rating) < 4.0) return false;
  if (f.max_price != null && Number(f.max_price) > 30.0) return false;
  return true;
}
function scienceFilterOk(f) {
  if (!f) return false;
  if (f.format !== 'paperback') return false;
  if (!(f.topic === 'cheese_science' || f.topic === 'modern_cheese_production')) return false;
  if (f.min_rating != null && Number(f.min_rating) < 4.0) return false;
  if (f.max_price != null && Number(f.max_price) > 25.0) return false;
  return true;
}
const filtersPassed = historyFilterOk(historyFilter) && scienceFilterOk(scienceFilter);
checkpoints.push({
  passed: filtersPassed,
  weight: 0.30
});

// Determine qualifying products in the current cart
const relevantCartItems = cartItems.filter(ci => ci.cart_id === currentCartId && ci.item_type === 'shop_product' && ci.quantity > 0);

const historyProductIds = new Set();
const scienceProductIds = new Set();
for (let i = 0; i < relevantCartItems.length; i++) {
  const ci = relevantCartItems[i];
  const p = products.find(pr => pr.id === ci.product_id);
  if (!p) continue;
  if (p.product_type !== 'book' || p.category !== 'books') continue;
  if (p.format !== 'paperback') continue;
  if (p.rating != null && p.rating < 4.0) continue;
  if (p.price == null) continue;
  // History group
  if (p.topic === 'european_cheese_history' && p.price < 30.0) {
    historyProductIds.add(p.id);
  }
  // Science/modern production group
  if ((p.topic === 'cheese_science' || p.topic === 'modern_cheese_production') && p.price < 25.0) {
    scienceProductIds.add(p.id);
  }
}

const historyCount = historyProductIds.size;
const scienceCount = scienceProductIds.size;

// CP2 (0.45): Cart contains at least 2 qualifying European cheese history paperbacks and 1 qualifying modern science/production paperback
checkpoints.push({
  passed: historyCount >= 2 && scienceCount >= 1,
  weight: 0.45
});

// Check selected shipping option
let selectedCart = null;
if (currentCartId) {
  selectedCart = carts.find(c => c.id === currentCartId) || null;
}
let selectedShipping = null;
if (selectedCart && selectedCart.selected_shipping_option_id) {
  selectedShipping = shippingOptions.find(so => so.id === selectedCart.selected_shipping_option_id) || null;
}
const shippingIsStandardDomestic = !!selectedShipping && selectedShipping.method_code === 'standard_domestic' && selectedShipping.is_active === true;

// CP3 (0.25): Cart viewed and standard domestic shipping selected, with qualifying books in cart
checkpoints.push({
  passed: cartViewed && shippingIsStandardDomestic && historyCount >= 2 && scienceCount >= 1,
  weight: 0.25
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseArrayLS(key) {
  try { return JSON.parse(localStorage.getItem(key) || '[]'); } catch (e) { return []; }
}

const subs = parseArrayLS('newsletter_subscriptions');
const subInterests = parseArrayLS('subscription_interests');

// Find subscription for visitor@example.com
