let hasAncient = false;
let hasEvents = false;
if (subscription) {
  const interestsForSub = subInterests.filter(i => i.subscription_id === subscription.id);
  for (let i = 0; i < interestsForSub.length; i++) {
    if (interestsForSub[i].interest_code === 'ancient_cheese_history') hasAncient = true;
    if (interestsForSub[i].interest_code === 'museum_events_workshops') hasEvents = true;
