checkpoints.push({
  passed: !!subscription && hasAncient && hasEvents,
  weight: 0.30
});

// CP3 (0.20): Subscription status is active, indicating follow-up preferences were completed
const statusPassed = !!subscription && subscription.status === 'active';
checkpoints.push({
  passed: statusPassed,
  weight: 0.20
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
